#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, P;
        scanf("%d %d", &N, &P);
        char SA[N*N*N], SB[N*N*N];
        scanf("%s", SA);
        scanf("%s", SB);
        int S = -1, count = 0;
        for (int size = N; size >= 1; size--) {
            int match = 0;
            for (int i = 0; i <= N - size; i++) {
                for (int j = 0; j <= N - size; j++) {
                    for (int k = 0; k <= N - size; k++) {
                        int equal = 0;
                        for (int x = 0; x < size; x++) {
                            for (int y = 0; y < size; y++) {
                                for (int z = 0; z < size; z++) {
                                    if (SA[(i+x)*N*N + (j+y)*N + (k+z)] == SB[(i+x)*N*N + (j+y)*N + (k+z)]) {
                                        equal++;
                                    }
                                }
                            }
                        }
                        if ((double)equal / (size*size*size) * 100 >= P) {
                            match++;
                        }
                    }
                }
            }
            if (match > 0) {
                S = size;
                count = match;
                break;
            }
        }
        if (S == -1) {
            printf("-1\n");
        } else {
            printf("%d %d\n", S, count);
        }
    }
    return 0;
}

